selector_to_html = {"a[href=\"#cpp-echo-camera-rgbd\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Depth Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-rgbd\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_rgbd</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgbd_head_front/</span></code> topic to receive depth camera data, supporting multiple data types including depth point clouds, depth images, RGB images, compressed RGB images, and camera intrinsic parameters.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-locomotion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.8 </span>Robot Locomotion Control<a class=\"headerlink\" href=\"#cpp-locomotion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mc_locomotion_velocity. The following example controls the robot\u2019s walking by publishing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/mc/locomotion/velocity</span></code> topic. For versions after v0.7, an input source must be registered before enabling velocity control (this example already includes input source registration). Refer to the code for detailed registration steps.</strong></p><p>Start the node after switching to Stable Standing Mode:</p>", "a[href=\"#cpp-joint-control\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Robot Joint Control Example<a class=\"headerlink\" href=\"#cpp-joint-control\" title=\"Link to this heading\">\uf0c1</a></h3><p>This example demonstrates how to control the robot\u2019s joints using ROS2 and the Ruckig library. It includes the following features:</p>", "a[href=\"#cpp-hand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.4 </span>Gripper Control<a class=\"headerlink\" href=\"#cpp-hand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses hand_control. By publishing messages to the topic <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code>, you can control the movement of the gripper.</strong></p>", "a[href=\"#cpp-example-build\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Build Instructions<a class=\"headerlink\" href=\"#cpp-example-build\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#cpp-example-explain\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Example Function Overview<a class=\"headerlink\" href=\"#cpp-example-explain\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#cpp-example-deps\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Dependencies<a class=\"headerlink\" href=\"#cpp-example-deps\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#cpp-play-tts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.17 </span>TTS (Text-to-Speech)<a class=\"headerlink\" href=\"#cpp-play-tts\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_tts</strong>, enabling the robot to speak the provided text. Users can input any text depending on the scenario.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-mic-receiver\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.18 </span>Microphone Audio Reception<a class=\"headerlink\" href=\"#cpp-mic-receiver\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses mic_receiver</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/agent/process_audio_output</span></code> topic to receive the robot\u2019s noise-reduced audio stream. It supports both internal and external microphone audio streams, and automatically saves complete speech segments as PCM files based on VAD (Voice Activity Detection) states.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-set-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.6 </span>Register Secondary Development Input Source<a class=\"headerlink\" href=\"#cpp-set-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>For versions after v0.7, an input source must be registered before controlling the MC. In this example, the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aimdk_5Fmsgs/srv/SetMcInputSource</span></code> service is used to register the secondary development input source, so that the MC can recognize it. Only after registration can robot velocity control be performed.</strong></p>", "a[href=\"#cpp-omnihand-control\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.5 </span>Dexterous Hand Control<a class=\"headerlink\" href=\"#cpp-omnihand-control\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses omnihand_control. By publishing messages to the topic <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/joint/hand/command</span></code>, you can control the movement of the omnihand.</strong></p>", "a[href=\"#cpp-echo-camera-stereo\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Stereo Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-stereo\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_stereo</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/stereo_head_front_*/</span></code> topics to receive stereo camera data, supporting RGB images, compressed images, and camera intrinsic parameters from both the left and right cameras.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-play-emoji\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.19 </span>Emoji Control<a class=\"headerlink\" href=\"#cpp-play-emoji\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_emoji</strong>, which allows the robot to display a specified emoji. Users can choose an emoji from the available list; see the <a class=\"reference internal\" href=\"../Interface/interactor/screen.html#tbl-emotion-id\"><span class=\"std std-ref\">Emoji List</span></a> for details.</p>", "a[href=\"#cpp-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.2 </span>Set Robot Mode<a class=\"headerlink\" href=\"#cpp-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"#cpp-example-expand\"]": "<h4 class=\"tippy-header\" style=\"margin-top: 0;\">Customization<a class=\"headerlink\" href=\"#cpp-example-expand\" title=\"Link to this heading\">\uf0c1</a></h4>", "a[href=\"#cpp-play-video\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.15 </span>Play Video<a class=\"headerlink\" href=\"#cpp-play-video\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_video.</strong> Before running the node, you must upload the video file to the robot\u2019s <strong>Interaction Computing Unit (PC3)</strong> (you may create a directory there to store videos, e.g. /var/tmp/videos/). Then, modify the <code class=\"docutils literal notranslate\"><span class=\"pre\">video_path</span></code> in the node program to the path of the video you want to play.</p>", "a[href=\"#cpp-echo-head-touch-sensor\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.13 </span>Head touch sensor data subscription<a class=\"headerlink\" href=\"#cpp-echo-head-touch-sensor\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_head_touch_sensor</strong>, which subscribes to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/touch_head</span></code> topic to receive the robot\u2019s touch sensor data on the head.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-preset-motion\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.3 </span>Set Robot Motion<a class=\"headerlink\" href=\"#cpp-preset-motion\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses <code class=\"docutils literal notranslate\"><span class=\"pre\">preset_motion_client</span></code></strong>; after switching to Stable Stand Mode and starting the node, enter the corresponding field values to perform preset actions with the left (or right) hand such as handshake, raise hand, wave, or air kiss.</p><p>Available parameters can be found in the <a class=\"reference internal\" href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"><span class=\"std std-ref\">Preset Motion Table</span></a></p>", "a[href=\"../Interface/control_mod/preset_motion.html#tbl-preset-motion\"]": "<table class=\"docutils align-default\" id=\"tbl-preset-motion\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Action Name</p></th>\n<th class=\"head\"><p><code class=\"docutils literal notranslate\"><span class=\"pre\">motion</span></code></p></th>\n<th class=\"head\"><p><code class=\"docutils literal notranslate\"><span class=\"pre\">area</span></code></p></th>\n<th class=\"head\"><p>Notes</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Right-hand wave</p></td>\n<td><p>1002</p></td>\n<td><p>2</p></td>\n<td><p>switch to Stable Stand first</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand wave</p></td>\n<td><p>1002</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand handshake</p></td>\n<td><p>1003</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand handshake</p></td>\n<td><p>1003</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand raise</p></td>\n<td><p>1001</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand raise</p></td>\n<td><p>1001</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand blow a kiss</p></td>\n<td><p>1004</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand blow a kiss</p></td>\n<td><p>1004</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Clap</p></td>\n<td><p>3017</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Right-hand salute</p></td>\n<td><p>1013</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Left-hand salute</p></td>\n<td><p>1013</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Heart gesture (both hands)</p></td>\n<td><p>1007</p></td>\n<td><p>3</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand heart gesture</p></td>\n<td><p>1007</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand heart gesture</p></td>\n<td><p>1007</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Hug</p></td>\n<td><p>3008</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Cheer</p></td>\n<td><p>3011</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Raise both hands</p></td>\n<td><p>1010</p></td>\n<td><p>3</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Raise right hand</p></td>\n<td><p>1010</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Raise left hand</p></td>\n<td><p>1010</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Wave goodbye</p></td>\n<td><p>3031</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Dynamic light wave</p></td>\n<td><p>3007</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Right-hand high-five</p></td>\n<td><p>1008</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Left-hand high-five</p></td>\n<td><p>1008</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Cross arms</p></td>\n<td><p>3009</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Right-hand wave at chest</p></td>\n<td><p>1011</p></td>\n<td><p>2</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Left-hand wave at chest</p></td>\n<td><p>1011</p></td>\n<td><p>1</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Bow</p></td>\n<td><p>3001</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Scratch head</p></td>\n<td><p>3024</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Grab buttocks</p></td>\n<td><p>3025</p></td>\n<td><p>11</p></td>\n<td><p>same as above</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#cpp-echo-lidar-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.14 </span>LiDAR Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-lidar-data\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses echo_lidar_data</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/lidar_chest_front/</span></code> topic to receive LiDAR data, supporting both point cloud data and IMU data types.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-motocontrol\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.9 </span>Joint Motor Control<a class=\"headerlink\" href=\"#cpp-motocontrol\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example demonstrates how to use ROS2 and the Ruckig library to control the robot\u2019s joint movements.</strong></p>", "a[href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"]": "<table class=\"docutils align-default\" id=\"tbl-mc-action\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Mode</p></th>\n<th class=\"head\"><p>Value</p></th>\n<th class=\"head\"><p>Description</p></th>\n<th class=\"head\"><p>Use cases</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>Zero-Torque Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">PASSIVE_DEFAULT</span></code></p></td>\n<td><p>Robot joints zero torque, free state</p></td>\n<td><p>System startup, maintenance, soft e-stop</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Damping Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">DAMPING_DEFAULT</span></code></p></td>\n<td><p>The joint exhibits a damping effect</p></td>\n<td><p>Safe movement</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Position-controlled Stand</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">JOINT_DEFAULT</span></code></p></td>\n<td><p>Position-controlled stand</p></td>\n<td><p>Precise joint position control</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>Stable Stand</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code></p></td>\n<td><p>Active force to ensure standing</p></td>\n<td><p>Dynamic balance control, walking/action ready state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>Locomotion Mode</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code></p></td>\n<td><p>Normal walking/running</p></td>\n<td><p>Daily movement</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#cpp-play-lights\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.20 </span>LED Strip Control<a class=\"headerlink\" href=\"#cpp-play-lights\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Function Description</strong>: Demonstrates how to control the robot\u2019s LED strip, supporting multiple display modes and customizable colors.</p><p><strong>Core Code</strong>:</p>", "a[href=\"#cpp-play-media\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.16 </span>Media File Playback<a class=\"headerlink\" href=\"#cpp-play-media\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses play_media</strong>, enabling playback of specified media files (such as audio files). It supports audio formats including WAV and MP3.</p><p><strong>Features:</strong></p>", "a[href=\"#cpp-echo-camera-head-rear\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rear Head Monocular Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-head-rear\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_head_rear</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgb_head_rear/</span></code> topic to receive data from the robot\u2019s rear head monocular camera, supporting RGB images (with/without mask), compressed images, and camera intrinsic parameters.</p><p><strong>Features:</strong></p>", "a[href=\"../Interface/interactor/screen.html#tbl-emotion-id\"]": "<table class=\"docutils align-default\" id=\"tbl-emotion-id\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Emoji ID</p></th>\n<th class=\"head\"><p>Emoji name</p></th>\n<th class=\"head\"><p>Description</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>1</p></td>\n<td><p>Blink</p></td>\n<td><p>Basic blink action</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>10</p></td>\n<td><p>Calm - eye variation 1</p></td>\n<td><p>Eye variation for calm state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>11</p></td>\n<td><p>Calm - eye variation 2</p></td>\n<td><p>Eye variation for calm state</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>20</p></td>\n<td><p>Calm - game</p></td>\n<td><p>Game-state emoji</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>30-33</p></td>\n<td><p>Calm - cute</p></td>\n<td><p>Cute expression series</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>40</p></td>\n<td><p>Close eyes</p></td>\n<td><p>Close-eye action</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>50</p></td>\n<td><p>Open eyes</p></td>\n<td><p>Open-eye action</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>60</p></td>\n<td><p>Bored</p></td>\n<td><p>Bored expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>70</p></td>\n<td><p>Abnormal</p></td>\n<td><p>Abnormal state</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>80</p></td>\n<td><p>Sleeping</p></td>\n<td><p>Sleeping state</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>90</p></td>\n<td><p>Happy</p></td>\n<td><p>Happy expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>100-101</p></td>\n<td><p>Extra happy / ecstatic</p></td>\n<td><p>Extremely happy expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>110</p></td>\n<td><p>Sad</p></td>\n<td><p>Sad expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>120</p></td>\n<td><p>Sympathy</p></td>\n<td><p>Sympathetic expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>130</p></td>\n<td><p>Confused</p></td>\n<td><p>Confused expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>140</p></td>\n<td><p>Shocked</p></td>\n<td><p>Shocked expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>150</p></td>\n<td><p>Acting cute</p></td>\n<td><p>Cute/affectionate expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>160</p></td>\n<td><p>Serious</p></td>\n<td><p>Serious expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>170</p></td>\n<td><p>Thinking</p></td>\n<td><p>Thinking expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>180</p></td>\n<td><p>Angry</p></td>\n<td><p>Angry expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>190</p></td>\n<td><p>Extra angry</p></td>\n<td><p>Extremely angry expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>200</p></td>\n<td><p>Adoration</p></td>\n<td><p>Adoring expression</p></td>\n</tr>\n<tr class=\"row-even\"><td><p>210</p></td>\n<td><p>Extra adoring</p></td>\n<td><p>Extremely adoring expression</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>220</p></td>\n<td><p>Charging</p></td>\n<td><p>Charging state</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#cpp-keyboard\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.10 </span>Keyboard Control of the Robot<a class=\"headerlink\" href=\"#cpp-keyboard\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example enables controlling the robot\u2019s forward, backward, and turning movements using PC keyboard input.</strong></p><p><strong>Use <kbd class=\"kbd docutils literal notranslate\">W</kbd> <kbd class=\"kbd docutils literal notranslate\">A</kbd> <kbd class=\"kbd docutils literal notranslate\">S</kbd> <kbd class=\"kbd docutils literal notranslate\">D</kbd> to control the walking direction, increase/decrease linear velocity (\u00b10.2 m/s), use <kbd class=\"kbd docutils literal notranslate\">Q</kbd> / <kbd class=\"kbd docutils literal notranslate\">E</kbd> to increase/decrease angular velocity (\u00b10.1 rad/s), <kbd class=\"kbd docutils literal notranslate\">ESC</kbd> exits the program and releases terminal resources, and <font style=\"color: red\"><kbd class=\"kbd docutils literal notranslate\">Space</kbd> immediately resets the velocity to zero to perform an emergency stop</font>.</strong></p>", "a[href=\"#cpp-echo-cameras\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.12 </span>Camera Streaming Example Collection<a class=\"headerlink\" href=\"#cpp-echo-cameras\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example set provides multiple camera data subscription and processing functions, supporting data streams from depth cameras, stereo cameras, and monocular cameras.</strong><br/>\nThese camera subscription examples do not provide actual application-level logic; they only print basic camera data information. If you are familiar with ROS2, you may notice that <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">echo</span></code> + <code class=\"docutils literal notranslate\"><span class=\"pre\">ros2</span> <span class=\"pre\">topic</span> <span class=\"pre\">hz</span></code> can also achieve similar functionality. You may directly check the topic list in the SDK interface manual to start developing your own module, or you may use these camera examples as scaffolding to integrate your own business logic.  <strong>All published sensor data is raw and unprocessed (e.g., without undistortion). If you need detailed sensor information (such as resolution, focal length, etc.), please refer to the <code class=\"docutils literal notranslate\"><span class=\"pre\">camera_info</span></code> topic.</strong></p>", "a[href=\"#cpp-take-photo\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.11 </span>Take Photo<a class=\"headerlink\" href=\"#cpp-take-photo\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses take_photo.</strong> Before running the node, modify the camera topic from which to capture the image. After starting the node, an <code class=\"docutils literal notranslate\"><span class=\"pre\">/images/</span></code> directory will be created, and the current frame will be saved into this directory.</p>", "a[href=\"#c\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2 </span>C++ Interface Usage Example<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This section will guide you through implementing the functions listed in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"#cpp-get-mc-input-source\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.7 </span>Get Current Input Source<a class=\"headerlink\" href=\"#cpp-get-mc-input-source\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the GetCurrentInputSource service</strong>, which is used to obtain information about the currently registered input source, including the input source name, priority, and timeout settings.</p>", "a[href=\"#cpp-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.1 </span>Get Robot Mode<a class=\"headerlink\" href=\"#cpp-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
